def test_payroll_run_500_rolls_back_atomically(
    hr_admin_token, seed_active_employees, inject_payroll_fault, api_client
):
    seed_active_employees(count=3)
    inject_payroll_fault(error_type="db_write", after_stubs=1)

    payload = {"period": "2024-07", "type": "monthly"}
    resp = api_client.post(
        "/api/payroll-runs",
        json=payload,
        headers={"Authorization": f"Bearer {hr_admin_token}"},
    )
    assert resp.status_code == 500
    body = resp.json()
    run_id = body.get("run_id")

    if run_id:
        stubs_resp = api_client.get(
            f"/api/payroll-runs/{run_id}/pay-stubs",
            headers={"Authorization": f"Bearer {hr_admin_token}"},
        )
        stubs = stubs_resp.json().get("items", [])
        assert len(stubs) == 0, "Partial stubs found — rollback failed"

    runs_resp = api_client.get(
        "/api/payroll-runs?period=2024-07",
        headers={"Authorization": f"Bearer {hr_admin_token}"},
    )
    completed = [
        r for r in runs_resp.json().get("items", [])
        if r["state"] in ("completed", "partial")
    ]
    assert len(completed) == 0
